import java.util.Scanner;

public class SecureBufferImplementation {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Defining a safe buffer size
        int bufferSize = Math.min(userInput.length(), 10);

        // Creating a character array with safe size
        char[] buffer = new char[bufferSize];

        // Copying user input into the safe-size buffer with proper bounds checking
        for (int i = 0; i < bufferSize; i++) {
            buffer[i] = userInput.charAt(i);
        }

        // Printing out the contents of the buffer
        System.out.println("Buffer contents: ");
        for (char c : buffer) {
            System.out.print(c);
        }
    }
}

